                            "tier": "junior",
                            "code": "// === JUNIOR EXAMPLE ===\n// TASK      - Real-world usage of Geolocation API — User Location — common patterns you'll see in production.\n// APPROACH  - Combine Geolocation API — User Location with related functions; handle common edge cases.\n// STRENGTHS - Practical; covers the 80% use cases encountered on the job.\n// WEAKNESSES- May need optimization for large datasets or complex queries.\n// APPROACH  - geolocation recipes: getCurrentPosition with options and error\n//             handling, watchPosition for continuous tracking, clearWatch to\n//             stop, Haversine distance, and a geofencing example.\n// STRENGTHS - covers the 80% case: one-shot, continuous tracking, distance,\n//             and geofencing with proper error codes.\n// WEAKNESSES- callback-based (no promise wrapper); no battery optimization.\n//\n// GOAL: get and track user location with error handling\n// WHY: geolocation requires HTTPS, user permission, and can time out\n// ── Get current location ──────────────────────────────\nfunction getLocation() {\n  if (!navigator.geolocation) {\n    console.error('Geolocation not supported');\n    return;\n  }\n  navigator.geolocation.getCurrentPosition(\n    (position) => {\n      const { latitude, longitude, accuracy } = position.coords;\n      console.log(`Location: ${latitude}, ${longitude} (±${accuracy}m)`);\n      showOnMap(latitude, longitude);\n    },\n    (error) => {\n      switch (error.code) {\n        case error.PERMISSION_DENIED:\n          console.error('User denied permission');\n          break;\n        case error.POSITION_UNAVAILABLE:\n          console.error('Location unavailable (no GPS, WiFi)');\n          break;\n        case error.TIMEOUT:\n          console.error('Location request timed out');\n          break;\n      }\n    },\n    {\n      enableHighAccuracy: true,  // use GPS (slower, more accurate)\n      timeout: 10000,            // wait max 10 seconds\n      maximumAge: 60000,         // cache for 1 minute\n    }\n  );\n}\n// ── Watch position (continuous tracking) ───────────────\nconst watchId = navigator.geolocation.watchPosition(\n  (position) => {\n    const { latitude, longitude, altitude, speed } = position.coords;\n    console.log(`Position: ${latitude}, ${longitude}, Speed: ${speed}m/s`);\n    updateMarkerOnMap(latitude, longitude);\n  },\n  (error) => {\n    console.error('Watch error:', error.message);\n  },\n  {\n    enableHighAccuracy: true,\n    timeout: 5000,\n    maximumAge: 0,  // get fresh location every time\n  }\n);\n// Stop watching\nbutton.addEventListener('click', () => {\n  navigator.geolocation.clearWatch(watchId);\n  console.log('Stopped tracking');\n});\n// ── Distance calculation (Haversine formula) ───────────\nfunction calculateDistance(lat1, lon1, lat2, lon2) {\n  const R = 6371; // Earth radius (km)\n  const φ1 = (lat1 * Math.PI) / 180;\n  const φ2 = (lat2 * Math.PI) / 180;\n  const Δφ = ((lat2 - lat1) * Math.PI) / 180;\n  const Δλ = ((lon2 - lon1) * Math.PI) / 180;\n  const a =\n    Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +\n    Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) * Math.sin(Δλ / 2);\n  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));\n  return R * c; // distance in km\n}\n// ── Geofencing example ────────────────────────────────\nconst geofence = { lat: 40.7128, lng: -74.006, radius: 0.5 }; // NYC, 500m\nconst geofenceWatchId = navigator.geolocation.watchPosition(\n  (position) => {\n    const { latitude, longitude } = position.coords;\n    const distance = calculateDistance(latitude, longitude, geofence.lat, geofence.lng);\n    if (distance < geofence.radius) {\n      console.log('Inside geofence!');\n    } else {\n      console.log('Outside geofence');\n    }\n  }\n);"
