                            "tier": "junior",
                            "code": "// === JUNIOR EXAMPLE ===\n// TASK      - Real-world usage of Web Share API — Native Sharing — common patterns you'll see in production.\n// APPROACH  - Combine Web Share API — Native Sharing with related functions; handle common edge cases.\n// STRENGTHS - Practical; covers the 80% use cases encountered on the job.\n// WEAKNESSES- May need optimization for large datasets or complex queries.\n// APPROACH  - Web Share recipes: basic share with canShare check, file sharing\n//             (screenshots), smart fallback to clipboard, conditional button\n//             visibility, and a social share fallback menu.\n// STRENGTHS - covers the 80% case: share text/url, share files, fallback to\n//             clipboard, and custom share UI for unsupported browsers.\n// WEAKNESSES- share() requires a user gesture; file sharing is Android-only.\n//\n// GOAL: trigger native sharing with graceful fallback\n// WHY: navigator.share only exists on supported (mostly mobile) platforms\n// ── Basic share (title, text, url) ─────────────────────\nconst shareButton = document.getElementById('share-btn');\nshareButton.addEventListener('click', async () => {\n  const shareData = {\n    title: 'Check this article',\n    text: 'This is a great read about web APIs',\n    url: window.location.href,\n  };\n  if (navigator.canShare?.(shareData)) {\n    try {\n      await navigator.share(shareData);\n      console.log('Shared successfully');\n    } catch (err) {\n      if (err.name !== 'AbortError') {\n        console.error('Share failed:', err);\n      }\n      // User cancelled, not an error\n    }\n  } else {\n    console.warn('Share not supported, show fallback UI');\n    showFallbackShareMenu();\n  }\n});\n// ── Share with file (mobile) ───────────────────────────\nasync function shareScreenshot() {\n  const canvas = document.getElementById('canvas');\n  const blob = await new Promise(resolve => canvas.toBlob(resolve));\n  const shareData = {\n    title: 'My screenshot',\n    text: 'Check out this screenshot!',\n    files: [new File([blob], 'screenshot.png', { type: 'image/png' })],\n  };\n  if (navigator.canShare?.(shareData)) {\n    await navigator.share(shareData);\n  }\n}\n// ── Share with fallback (copy link) ────────────────────\nasync function smartShare(data) {\n  if (navigator.share) {\n    try {\n      await navigator.share(data);\n      return;\n    } catch (err) {\n      // User cancelled\n      if (err.name === 'AbortError') return;\n    }\n  }\n  // Fallback: copy URL to clipboard\n  if (navigator.clipboard) {\n    await navigator.clipboard.writeText(data.url);\n    showNotification('Link copied to clipboard!');\n  } else {\n    showFallbackShareUI(data);\n  }\n}\n// ── Check canShare before showing button ────────────────\nfunction updateShareButton() {\n  const shareBtn = document.getElementById('share-btn');\n  const shareData = {\n    title: 'Article',\n    text: 'Check this out',\n    url: window.location.href,\n  };\n  if (navigator.canShare?.(shareData)) {\n    shareBtn.style.display = 'block'; // show share button\n  } else {\n    shareBtn.style.display = 'none'; // hide if not supported\n  }\n}\n// ── Full social share fallback ────────────────────────\nfunction showFallbackShareMenu() {\n  const url = encodeURIComponent(window.location.href);\n  const title = encodeURIComponent(document.title);\n  const shareLinks = {\n    twitter: `https://twitter.com/intent/tweet?url=${url}&text=${title}`,\n    facebook: `https://www.facebook.com/sharer/sharer.php?u=${url}`,\n    linkedin: `https://www.linkedin.com/sharing/share-offsite/?url=${url}`,\n    email: `mailto:?subject=${title}&body=${url}`,\n  };\n  // Show UI with these links\n}"
